Here's the Python function that counts the number of subarrays in `nums` that match the given `pattern`:

```python
def count_matching_subarrays(nums, pattern):
    m = len(pattern)
    count = 0
    n = len(nums)

    for i in range(n - m):
        match = True
        for k in range(m):
            if pattern[k] == 1 and nums[i + k + 1] <= nums[i + k]:
                match = False
                break
            elif pattern[k] == -1 and nums[i + k + 1] >= nums[i + k]:
                match = False
                break
            elif pattern[k] == 0 and nums[i + k + 1] != nums[i + k]:
                match = False
                break
        if match:
            count += 1
    return count
